create table dirkspzm32.edi_vda4987_serial (
    document_id     varchar2(32 char) not null enable,
    pack_item_id    varchar2(32 char),
    article_id      varchar2(32 char),
    serial_group_id varchar2(32 char) not null enable,
    pos             number(4, 0) not null enable,
    sn1a            varchar2(35 char),
    sn1b            varchar2(35 char),
    sn2a            varchar2(35 char),
    sn2b            varchar2(35 char),
    sn3a            varchar2(35 char),
    sn3b            varchar2(35 char),
    sn4a            varchar2(35 char),
    sn4b            varchar2(35 char),
    sn5a            varchar2(35 char),
    sn5b            varchar2(35 char)
);

alter table dirkspzm32.edi_vda4987_serial
    add constraint pk_edi_vda4987_serial primary key ( serial_group_id,
                                                       pos )
        using index enable;


